class Solution(object):
    def removeSubstring(self, s, k):
        # Use run-length encoding approach with a stack of (char, count) pairs
        # When top two are '(' run of count a and ')' run of count b,
        # we can remove min(a//k, b//k)*k from each.
        stack = []  # list of [char, count]

        for c in s:
            if stack and stack[-1][0] == c:
                stack[-1][1] += 1
            else:
                stack.append([c, 1])

            # Try to cancel: if top is ')' and second is '('
            while len(stack) >= 2 and stack[-1][0] == ')' and stack[-2][0] == '(':
                open_count = stack[-2][1]
                close_count = stack[-1][1]
                remove = min(open_count // k, close_count // k) * k
                if remove == 0:
                    break
                stack[-2][1] -= remove
                stack[-1][1] -= remove
                if stack[-1][1] == 0:
                    stack.pop()
                if stack and stack[-1][1] == 0:
                    stack.pop()
                # After removals, merge if needed (top might match new top)
                if len(stack) >= 2 and stack[-1][0] == stack[-2][0]:
                    stack[-2][1] += stack[-1][1]
                    stack.pop()

        return ''.join(c * cnt for c, cnt in stack)
